   872→/// Convert to an integer of the same size.
   873→SDValue DAGTypeLegalizer::BitConvertToInteger(SDValue Op) {
   874→  unsigned BitWidth = Op.getValueSizeInBits();
   875→  return DAG.getNode(ISD::BITCAST, SDLoc(Op),
