   324→        Changed = true;
   325→        break;
   326→      case TargetLowering::TypeExpandInteger:
   327→        NeedsReanalyzing = ExpandIntegerOperand(N, i);
   328→        Changed = true;
   329→        break;
   330→      case TargetLowering::TypeSoftenFloat:
   331→        NeedsReanalyzing = SoftenFloatOperand(N, i);
   332→        Changed = true;
   333→        break;
   334→      case TargetLowering::TypeExpandFloat:
   335→        NeedsReanalyzing = ExpandFloatOperand(N, i);
   336→        Changed = true;
